#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAXURL 105
#define BASE 62
const char charset[] = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ";

void encode(long long num, char *out) {
    char buf[20];
    int idx = 0;
    if (num == 0) {
        buf[idx++] = '0';
    } else {
        while (num > 0) {
            buf[idx++] = charset[num % BASE];
            num /= BASE;
        }
    }
    for (int i = 0; i < idx; ++i) out[i] = buf[idx - i - 1];
    out[idx] = '\0';
}

typedef struct { char key[MAXURL]; char val[10]; int used; } Pair;

unsigned long hash_str(const char *s) {
    unsigned long h = 5381;
    while (*s) h = ((h << 5) + h) + (unsigned char)*s++;
    return h;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int Q; if (scanf("%d", &Q) != 1) return 0;
        int size = 1; while (size < Q * 4) size <<= 1;
        Pair *url2code = calloc(size, sizeof(Pair));
        Pair *code2url = calloc(size, sizeof(Pair));
        long long nextId = 1;
        char op[10], arg[MAXURL];
        for (int i = 0; i < Q; ++i) {
            if (scanf("%s %s", op, arg) != 2) break;
            if (strcmp(op, "SHORTEN") == 0) {
                unsigned long h = hash_str(arg) & (size - 1);
                while (url2code[h].used && strcmp(url2code[h].key, arg) != 0) h = (h + 1) & (size - 1);
                if (url2code[h].used) {
                    printf("%s\n", url2code[h].val);
                } else {
                    char code[10]; encode(nextId++, code);
                    strcpy(url2code[h].key, arg);
                    strcpy(url2code[h].val, code);
                    url2code[h].used = 1;
                    unsigned long hc = hash_str(code) & (size - 1);
                    while (code2url[hc].used) hc = (hc + 1) & (size - 1);
                    strcpy(code2url[hc].key, code);
                    strcpy(code2url[hc].val, arg);
                    code2url[hc].used = 1;
                    printf("%s\n", code);
                }
            } else { // GET
                unsigned long h = hash_str(arg) & (size - 1);
                while (code2url[h].used && strcmp(code2url[h].key, arg) != 0) h = (h + 1) & (size - 1);
                if (code2url[h].used) {
                    printf("%s\n", code2url[h].val);
                } else {
                    printf("error\n");
                }
            }
        }
        free(url2code);
        free(code2url);
    }
    return 0;
}

