#include <bits/stdc++.h>
using namespace std;

const string charset = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ";
string encode(long long num) {
    if (num == 0) return "0";
    string s;
    while (num > 0) {
        s.push_back(charset[num % 62]);
        num /= 62;
    }
    reverse(s.begin(), s.end());
    return s;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    while (T--) {
        int Q; cin >> Q;
        unordered_map<string,string> url2code, code2url;
        long long nextId = 1;
        for (int i = 0; i < Q; ++i) {
            string op, arg; cin >> op >> arg;
            if (op == "SHORTEN") {
                auto it = url2code.find(arg);
                if (it != url2code.end()) {
                    cout << it->second << '\n';
                } else {
                    string code = encode(nextId++);
                    url2code[arg] = code;
                    code2url[code] = arg;
                    cout << code << '\n';
                }
            } else { // GET
                auto it = code2url.find(arg);
                if (it != code2url.end()) cout << it->second << '\n';
                else cout << "error" << '\n';
            }
        }
    }
    return 0;
}

