import java.io.*;
import java.util.*;

public class Main {
    private static final char[] CHARSET = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ".toCharArray();
    private static String encode(long num) {
        if (num == 0) return "0";
        StringBuilder sb = new StringBuilder();
        while (num > 0) {
            sb.append(CHARSET[(int)(num % 62)]);
            num /= 62;
        }
        return sb.reverse().toString();
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            int Q = Integer.parseInt(br.readLine().trim());
            Map<String, String> url2code = new HashMap<>();
            Map<String, String> code2url = new HashMap<>();
            long nextId = 1;
            for (int i = 0; i < Q; ++i) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                String op = st.nextToken();
                String arg = st.nextToken();
                if (op.equals("SHORTEN")) {
                    String code = url2code.get(arg);
                    if (code == null) {
                        code = encode(nextId++);
                        url2code.put(arg, code);
                        code2url.put(code, arg);
                    }
                    out.append(code).append('\n');
                } else { // GET
                    String url = code2url.get(arg);
                    out.append(url == null ? "error" : url).append('\n');
                }
            }
        }
        System.out.print(out.toString());
    }
}

