#!/usr/bin/env python3
import sys

charset = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ"

def encode(num: int) -> str:
    if num == 0:
        return "0"
    s = []
    while num:
        s.append(charset[num % 62])
        num //= 62
    return ''.join(reversed(s))

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx].strip()); idx += 1
    out_lines = []
    for _ in range(T):
        Q = int(data[idx].strip()); idx += 1
        url2code = {}
        code2url = {}
        nxt = 1
        for _ in range(Q):
            op, arg = data[idx].split(' ', 1)
            idx += 1
            if op == 'SHORTEN':
                if arg in url2code:
                    out_lines.append(url2code[arg])
                else:
                    code = encode(nxt)
                    nxt += 1
                    url2code[arg] = code
                    code2url[code] = arg
                    out_lines.append(code)
            else:  # GET
                out_lines.append(code2url.get(arg, 'error'))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

